# [doc = " A small, dependency-free client-side substring filter over `search-index.json` — no search"] # [doc = " engine, no heavy dep; keeps the crate's dependency posture (KC-3)."] const SEARCH_JS : & str = "\
async function mycBookSearch() {
  const res = await fetch('search-index.json');
  const records = await res.json();
  const input = document.getElementById('book-search-box');
  const out = document.getElementById('book-search-results');
  function render(q) {
    out.innerHTML = '';
    if (!q) { return; }
    const needle = q.toLowerCase();
    const hits = records.filter(r =>
      r.title.toLowerCase().includes(needle) ||
      r.chapter.toLowerCase().includes(needle) ||
      r.snippet.toLowerCase().includes(needle)
    );
    for (const r of hits) {
      const li = document.createElement('li');
      const a = document.createElement('a');
      a.href = r.url;
      a.textContent = r.title + ' (' + r.chapter + ')';
      li.appendChild(a);
      out.appendChild(li);
    }
    if (hits.length === 0) {
      out.innerHTML = '<li>No matches.</li>';
    }
  }
  input.addEventListener('input', () => render(input.value));
}
mycBookSearch();
" ;
